from typing import Protocol

class Speaker(Protocol):
    def speak(self) -> str: ...

class Dog:
    def speak(self) -> str:
        return "woof"

class Rock:
    pass

def announce(s: Speaker) -> None:
    print(s.speak())

announce(Dog())
announce(Rock())

from collections.abc import Callable

def apply_twice(f: Callable[[int], int], x: int) -> int:
    return f(f(x))

print(apply_twice(lambda n: n * 3, 2))
